import{_ as t,o as a,c as l,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Alliance Brawl","description":"","frontmatter":{},"headers":[],"relativePath":"events/alliance-brawl.md","filePath":"events/alliance-brawl.md"}'),r={name:"events/alliance-brawl.md"};function s(i,e,n,h,c,d){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="alliance-brawl" tabindex="-1">Alliance Brawl <a class="header-anchor" href="#alliance-brawl" aria-label="Permalink to &quot;Alliance Brawl&quot;">​</a></h1><p>Alliance Brawl is the default multi-stage template for the long brawl event with daily stages and one overall total view.</p><blockquote><p>Screenshot placeholder: import-stage-picker.png</p></blockquote><h2 id="how-this-default-is-set-up" tabindex="-1">How this default is set up <a class="header-anchor" href="#how-this-default-is-set-up" aria-label="Permalink to &quot;How this default is set up&quot;">​</a></h2><ul><li>event style: multi-stage</li><li>score entry: one score per row</li><li>default stage count: 6</li><li>default duration: 7 days</li><li>participation tracked: yes</li></ul><p>This event is stage-based, so the stage choice on import matters a lot.</p><h2 id="the-important-import-rule" tabindex="-1">The important import rule <a class="header-anchor" href="#the-important-import-rule" aria-label="Permalink to &quot;The important import rule&quot;">​</a></h2><p>When you upload results for Alliance Brawl, you must choose one of these on purpose:</p><ul><li><strong>Stage Data</strong> and the matching day number</li><li><strong>Total Data</strong> for the overall standings</li></ul><p>For this default, stage selection is not optional or automatic.</p><p>That means:</p><ul><li>if your screenshot shows Day 1 results, import it as <strong>Stage Data</strong> and choose <strong>Stage 1</strong></li><li>if your screenshot shows the overall event standings, import it as <strong>Total Data</strong></li></ul><p>Do not upload a day screenshot while leaving the stage unclear and expect the tracker to guess.</p><h2 id="why-the-stage-choice-matters" tabindex="-1">Why the stage choice matters <a class="header-anchor" href="#why-the-stage-choice-matters" aria-label="Permalink to &quot;Why the stage choice matters&quot;">​</a></h2><p>Alliance Brawl usually needs two different views:</p><ul><li>per-day stage results</li><li>an overall total or final standings view</li></ul><p>Choosing the wrong mode mixes those two ideas and makes reports harder to trust.</p><h2 id="suggested-workflow" tabindex="-1">Suggested workflow <a class="header-anchor" href="#suggested-workflow" aria-label="Permalink to &quot;Suggested workflow&quot;">​</a></h2><ol><li>Create the instance with the full date range.</li><li>Check the stage dates if your team wants them filled in.</li><li>Import each day&#39;s screenshot as <strong>Stage Data</strong>.</li><li>Import the overall standings separately as <strong>Total Data</strong>, if you track it.</li></ol><h2 id="protection-note" tabindex="-1">Protection note <a class="header-anchor" href="#protection-note" aria-label="Permalink to &quot;Protection note&quot;">​</a></h2><p>This is a default template, so it is <strong>editable but not deletable</strong>. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./default-events.html">The Default Events</a></li><li><a href="./../how-to/create-instance.html">Create an Event Instance</a></li><li><a href="./../imports/upload-screenshots.html">Upload Screenshots</a></li><li><a href="./../how-to/instance-detail.html">Work Inside an Instance</a></li></ul>',23)])])}const g=t(r,[["render",s]]);export{p as __pageData,g as default};
